+
+    #[test]
+    fn jsonl_field_values_accurate() {
+        let e = EvidenceEntry {
+            frame: 7,
+            value: 123.45,
+            residual: -0.5678,
+            cusum_upper: 3.1415,
+            cusum_lower: 0.0,
