+        assert!(line.contains("\"mean\":120.00"));
+        assert!(line.contains("\"sigma\":4.5678"));
+    }
+
+    #[test]
+    fn jsonl_contains_e_value_key() {
+        let e = EvidenceEntry {
+            frame: 1,
+            value: 0.0,
+            residual: 0.0,
+            cusum_upper: 0.0,
+            cusum_lower: 0.0,
+            e_value: 1.0,
+            mean_estimate: 0.0,
+            sigma_estimate: 1.0,
